    # Check if command is in whitelist
    if cmd not in allowed_commands:
        print("Command not allowed.")
        return

    # Additional check: ensure no shell metacharacters in any part
    dangerous_chars = {';', '|', '&', '$', '`', '>', '<', '*', '?', '{', '}', '(', ')', '[', ']', '~', '!', '#'}
    for part in parts:
        for char in dangerous_chars:
